struct Info {
	Info() :val(-LNF), id(0) {}
	Info(ll val, ll id) :val(val), id(id) {}
	ll val, id;
};

Info operator+(const Info& lower, const Info& upper) {
	Info res;
	if (lower.val > upper.val)res = lower;
	else res = upper;
	return res;
}

void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var e = vector<pair<ll, tuple<int, int, int>>>(m + 1);
	var c = vector<ll>(m + 1);
	fa(i, 1, m)cin >> e[i].px;
	fa(i, 1, m)cin >> c[i];
	fa(i, 1, m) {
		int u, v; cin >> u >> v;
		e[i].py = { u,v,i };
	}
	ll S; cin >> S;

	// 最小生成树 + 建图
	sort(all1(e));
	var s = vector<int>(n + 1);
	fa(i, 1, n)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		return s[x] = find(find, s[x]);
		};

	var g = vector<vector<tuple<int, ll, int>>>(n + 1); // { to, w, id }
	var vis = vector<bool>(m + 1);
	ll mst_val = 0, cnt = n - 1ll;
	ll mnc = LNF, mncid = 0;
	var mst = vector<pll>();
	fa(i, 1, m) {
		const var& [w, tmp] = e[i];
		const var& [x, y, id] = tmp;
		int e1 = find(find, x);
		int e2 = find(find, y);
		if (e1 != e2) {
			s[e2] = e1;
			cnt--;
			g[x].pb({ y,w,id });
			g[y].pb({ x,w,id });

			mst_val += w;
			vis[id] = 1;
			if (mnc > c[id]) { // 找出最小 c
				mnc = c[id];
				mncid = id;
			}
			mst.pb({ id,w });

			if (!cnt)break;
		}
	}

	// 倍增 和 lca
	var dp = Vec2<Info>(n + 1, 21);
	var dep = vector<int>(n + 1);
	var p = Vec2<int>(n + 1, 21);
	var dfs = [&](var dfs, int now, int fa)->void {
		dep[now] = dep[fa] + 1;
		p[now][0] = fa;
		for (const var& [to, w, id] : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			dp[to][0] = { w,id };
		}
		};
	dfs(dfs, 1, 0);

	var lca = [&dep, &p](int x, int y)->int {
		if (dep[x] < dep[y])swap(x, y);
		for (int i = 20; i >= 0; i--)
			if (dep[x] - (1 << i) >= dep[y])
				x = p[x][i];
		if (x == y) return x;
		for (int i = 20; i >= 0; i--)
			if (p[x][i] != p[y][i])
				x = p[x][i], y = p[y][i];
		return p[x][0];
		};

	var jump = [&](int now, int cha)->Info {
		Info res;
		fa(i, 0, 20)if (cha & (1 << i)) {
			res = res + dp[now][i];
			now = p[now][i];
		}
		return res;
		};

	fa(j, 1, 20) {
		fa(i, 1, n) {
			p[i][j] = p[p[i][j - 1]][j - 1];
			dp[i][j] = dp[i][j - 1] + dp[p[i][j - 1]][j - 1];
		}
	}

	// 开始算答案
	ll ans = mst_val - S / mnc;
	var out = mst;
	for (var& [id, w] : out) {
		if (id == mncid) {
			w -= S / mnc;
			break;
		}
	}

	fa(i, 1, m) {
		const var& [w, tmp] = e[i];
		const var& [x, y, id] = tmp;
		if (vis[id] or c[id] >= mnc)continue;
		int l = lca(x, y);

		Info info;
		if (l == y)info = jump(x, dep[x] - dep[l]);
		else if (l == x)info = jump(y, dep[y] - dep[l]);
		else info = jump(x, dep[x] - dep[l]) + jump(y, dep[y] - dep[l]);

		ll res = mst_val - info.val + w - S / c[id];
		if (ans > res) {
			ans = res;
			var nout = vector<pll>();
			for (const var& [id, w] : mst) {
				if (id != info.id)nout.pb({ id,w });
			}
			nout.pb({ id,w - S / c[id] });
			out = move(nout);
		}
	}

	cout << ans << endl;
	for (const var& [id, w] : out)cout << id << ' ' << w << endl;
	return;
}
